def predict_probability(x):
    margin = predict_raw_margin(x)
    # Sigmoid function for binary logistic regression probability
    try:
        prob = 1.0 / (1.0 + math.exp(-margin))
    except OverflowError:
        prob = 0.0 if margin < 0 else 1.0
    return prob
